// BTButton types — Figma source: node 114:2645.

/// Visual style of the button.
enum BTButtonVariant {
  primary,

  /// Neutral grey background (bg.secondary / #ecedee).
  secondaryLight,

  /// White background with a border (bg.primary + border.primary).
  secondaryWhite,

  destructive,
  outline,
  ghost,
}

/// Padding scale.
enum BTButtonSize {
  /// Default — 12 px vertical × 16 px horizontal. Total: 40 px height / 40×40 icon-only.
  md,

  /// Small — 8 px on all sides. Total: 32 px height / 32×32 icon-only.
  sm,

  /// Large — 16 px vertical × 24 px horizontal. Total: 48 px height / 48×48 icon-only.
  lg,
}

/// BTButton — interactive action atom.
/// Figma source: node 114:2645.
///
/// Width is intrinsic — the button never expands to fill its parent.
/// Wrap in [Expanded] or set an explicit width when full-width is needed.
///
/// Pass [onPressed] as `null` to disable.
///
/// ## Animation model
///
/// The pressed state is driven by a single [AnimationController] (120 ms
/// forward / 180 ms reverse).  Two fixes vs the previous implementation:
///
/// **Quick tap** — `_onTapDown` starts the forward animation and sets a
/// `_pendingRelease` flag.  When the animation completes naturally it checks
/// the flag and reverses; `_onTapUp` only calls `reverse()` immediately if
/// the animation is already at its upper bound.  This guarantees the pressed
/// visual is always visible even for a 20 ms tap.
///
/// **Shadow sync** — the inner shadow opacity is encoded in `shadowColor.alpha`
/// (lerped from 0 → full by the [AnimatedBuilder] on every frame).
/// [BTInnerShadowContainer] is a plain stateless widget with no internal
/// [AnimatedOpacity] or [AnimatedContainer], so shadow and background colour
/// are always in perfect sync — zero lag.
///
/// ## Usage:
/// ```dart
/// // Primary (default)
/// BTButton(label: 'Save', onPressed: handleSave)
///
/// // With left icon
/// BTButton(
///   label: 'Upload',
///   variant: BTButtonVariant.secondaryLight,
///   leftIcon: const Icon(Icons.upload, size: 16),
///   onPressed: handleUpload,
/// )
///
/// // Icon only
/// BTButton.iconOnly(
///   icon: const Icon(Icons.close, size: 16),
///   variant: BTButtonVariant.ghost,
///   onPressed: handleClose,
/// )
///
/// // Disabled (onPressed = null)
/// BTButton(label: 'Submit', onPressed: null)
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/button/button.types.dart';
import 'package:btech_ui/src/components/atoms/button/internal/button.colors.dart';
import 'package:btech_ui/src/components/atoms/button/internal/inner_shadow_container.dart';
import 'package:flutter/material.dart';

/// Action button atom. See file header for usage examples.
class BTButton extends StatefulWidget {
  /// Standard button with an optional text [label] and optional icons.
  const BTButton({
    required this.onPressed,
    this.label,
    this.variant = BTButtonVariant.primary,
    this.size = BTButtonSize.md,
    this.leftIcon,
    this.rightIcon,
    super.key,
  })  : _iconOnly = false,
        _icon = null;

  /// Square button that shows a single [icon] — no label.
  ///
  /// Pass [leftIcon] or [rightIcon] (e.g. a [BTHint] badge) to render an
  /// addon alongside the main icon.  When an addon is present the button
  /// sizes by padding + content instead of using the fixed square dimension.
  const BTButton.iconOnly({
    required Widget icon,
    required this.onPressed,
    this.variant = BTButtonVariant.primary,
    this.size = BTButtonSize.md,
    this.leftIcon,
    this.rightIcon,
    super.key,
  })  : _iconOnly = true,
        _icon = icon,
        label = null;

  /// Text shown inside the button (ignored in icon-only mode).
  final String? label;

  /// Visual style.
  final BTButtonVariant variant;

  /// Padding scale. [BTButtonSize.md] = 12×16 px, [BTButtonSize.sm] = 8 px, [BTButtonSize.lg] = 16×24 px.
  final BTButtonSize size;

  /// Callback invoked on tap. `null` disables the button.
  final VoidCallback? onPressed;

  /// Widget rendered to the left of [label] (16×16 recommended).
  final Widget? leftIcon;

  /// Widget rendered to the right of [label] (16×16 recommended).
  final Widget? rightIcon;

  final bool _iconOnly;
  final Widget? _icon;

  @override
  State<BTButton> createState() => _BTButtonState();
}

class _BTButtonState extends State<BTButton>
    with SingleTickerProviderStateMixin {
  // ── Animation ──────────────────────────────────────────────────────────────
  // 120 ms forward (linear) / 180 ms reverse (easeIn).
  // See class-level doc for the "quick tap" and "shadow sync" design notes.

  late final AnimationController _ctrl;
  late final Animation<double> _pressAnim;

  /// Set to true in _onTapUp if the forward animation hasn't completed yet.
  /// The forward completion listener checks this flag and starts the reverse.
  bool _pendingRelease = false;

  @override
  void initState() {
    super.initState();
    _ctrl = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 120),
      reverseDuration: const Duration(milliseconds: 180),
      value: 0,
    );
    _pressAnim = CurvedAnimation(
      parent: _ctrl,
      curve: Curves.linear,
      reverseCurve: Curves.easeInCubic,
    );

    // When the forward animation completes, start the reverse immediately
    // if the user has already released (quick tap path).
    _ctrl.addStatusListener(_onAnimationStatus);
  }

  void _onAnimationStatus(AnimationStatus status) {
    if (status == AnimationStatus.completed && _pendingRelease) {
      _pendingRelease = false;
      _ctrl.reverse();
    }
  }

  @override
  void dispose() {
    _ctrl.removeStatusListener(_onAnimationStatus);
    _ctrl.dispose();
    super.dispose();
  }

  bool get _disabled => widget.onPressed == null;

  // ── Gesture handlers ───────────────────────────────────────────────────────

  void _onTapDown(TapDownDetails _) {
    if (_disabled) return;
    _pendingRelease = false;
    // If already at the upper bound (rapid re-tap) reset to 0 so the full
    // press animation replays and the status listener doesn't fire immediately.
    if (_ctrl.value >= 1.0) _ctrl.value = 0.0;
    _ctrl.forward();
  }

  void _onTapUp(TapUpDetails _) {
    if (_disabled) return;
    if (_ctrl.status == AnimationStatus.completed) {
      // Animation already at peak — reverse immediately.
      _ctrl.reverse();
    } else {
      // Still animating forward — let the status listener handle the reverse
      // once forward() reaches 1.0 (guarantees pressed state is visible for
      // at least the full 120 ms even on the quickest tap).
      _pendingRelease = true;
    }
  }

  void _onTapCancel() {
    if (_disabled) return;
    _pendingRelease = false;
    _ctrl.reverse();
  }

  void _onTap() => widget.onPressed?.call();

  // ── Helpers ────────────────────────────────────────────────────────────────

  /// Lerps two colours without the "dark flash" caused by [Colors.transparent].
  ///
  /// `Color.lerp(Colors.transparent, someColor, t)` passes through dark
  /// semi-transparent tones because `Colors.transparent` == `0x00000000`
  /// (black at alpha 0).  For a hue-neutral fade we replace a fully-transparent
  /// `from` with a zero-alpha version of `to` so only alpha changes mid-lerp.
  ///
  ///   ghost idle → `Colors.transparent` (0x00000000)  ← broken without fix
  ///   ghost idle → `Color(0x00DADDE1)`               ← correct
  static Color _safeLerp(Color from, Color to, double t) {
    final effective = from.alpha == 0
        ? Color.fromARGB(0, to.red, to.green, to.blue)
        : from;
    return Color.lerp(effective, to, t) ?? from;
  }

  // ── Build ──────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final radius = context.btRadius.sm;
    final isSmall = widget.size == BTButtonSize.sm;
    final isLarge = widget.size == BTButtonSize.lg;
    final isIconOnly = widget._iconOnly;
    final hasAddon = isIconOnly &&
        (widget.leftIcon != null || widget.rightIcon != null);

    // Resolve colour anchors — idle and fully-pressed.
    // AnimatedBuilder lerps between them on every frame using _pressAnim.value.
    final idleCol = buttonColors(
      variant: widget.variant,
      state: BTButtonStateExt.of(
        disabled: _disabled,
        hovered: false,
        pressed: false,
      ),
      colors: colors,
    );
    final pressedCol = buttonColors(
      variant: widget.variant,
      state: BTButtonStateExt.of(
        disabled: false,
        hovered: true,
        pressed: true,
      ),
      colors: colors,
    );

    final padding = isIconOnly
        ? EdgeInsets.all(isSmall ? 8.0 : isLarge ? 16.0 : 12.0)
        : EdgeInsets.symmetric(
            vertical: isSmall ? 8.0 : isLarge ? 16.0 : 12.0,
            horizontal: isSmall ? 8.0 : isLarge ? 24.0 : 16.0,
          );
    final gap = isSmall ? 2.0 : 4.0;
    // Fixed dimensions — matches Figma icon-only square and regular height.
    // md: 40px · sm: 32px · lg: 48px
    final btnSize = isSmall ? 32.0 : isLarge ? 48.0 : 40.0;

    // Base shadow colour from design tokens — alpha will be lerped via t.
    final shadowBase = BTShadow.button.pressed.first.color;

    final Widget button = MouseRegion(
      cursor:
          _disabled ? SystemMouseCursors.forbidden : SystemMouseCursors.click,
      child: GestureDetector(
        onTap: _disabled ? null : _onTap,
        onTapDown: _disabled ? null : _onTapDown,
        onTapUp: _disabled ? null : _onTapUp,
        onTapCancel: _disabled ? null : _onTapCancel,
        child: IntrinsicWidth(
          child: AnimatedBuilder(
            animation: _pressAnim,
            builder: (context, _) {
              final t = _pressAnim.value;

              // ── Colour lerp ─────────────────────────────────────────────
              // Use _safeLerp so ghost/outline/secondaryWhite variants that
              // start with Colors.transparent don't flash a dark tint mid-lerp.
              final bg = _safeLerp(idleCol.bg, pressedCol.bg, t);
              final fg = _safeLerp(idleCol.fg, pressedCol.fg, t);

              final idleBorder = idleCol.border ?? Colors.transparent;
              final pressBorder = pressedCol.border ?? Colors.transparent;
              final borderColor = _safeLerp(idleBorder, pressBorder, t);
              final border =
                  (idleCol.border != null || pressedCol.border != null)
                      ? Border.all(color: borderColor)
                      : null;

              // ── Shadow alpha — perfectly synced with t, zero lag ────────
              // Encode visibility in alpha so BTInnerShadowContainer needs no
              // internal AnimatedOpacity.  Painter exits immediately at alpha=0.
              final shadowColor = _disabled
                  ? Colors.transparent
                  : Color.fromARGB(
                      (shadowBase.alpha * t).round(),
                      shadowBase.red,
                      shadowBase.green,
                      shadowBase.blue,
                    );

              // ── Content ─────────────────────────────────────────────────
              Widget content;
              if (isIconOnly) {
                final iconThemed = IconTheme(
                  data: IconThemeData(size: 16, color: fg),
                  child: widget._icon!,
                );
                if (hasAddon) {
                  // Icon-only with addon: render left/main/right in a Row.
                  // The outer SizedBox constraint is skipped so the button
                  // sizes by padding + content (same as web bt-button--has-addon).
                  content = Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      if (widget.leftIcon != null) ...[
                        widget.leftIcon!,
                        SizedBox(width: gap),
                      ],
                      SizedBox(
                        width: 16.0,
                        height: 16.0,
                        child: Center(child: iconThemed),
                      ),
                      if (widget.rightIcon != null) ...[
                        SizedBox(width: gap),
                        widget.rightIcon!,
                      ],
                    ],
                  );
                } else {
                  // Plain icon-only: constrain to 16×16, outer SizedBox.square
                  // enforces the total square dimension.
                  content = SizedBox(
                    width: 16.0,
                    height: 16.0,
                    child: Center(child: iconThemed),
                  );
                }
              } else {
                content = Row(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    if (widget.leftIcon != null) ...[
                      IconTheme(
                        data: IconThemeData(size: 16, color: fg),
                        child: widget.leftIcon!,
                      ),
                      SizedBox(width: gap),
                    ],
                    if (widget.label != null)
                      Text(
                        widget.label!,
                        style: TextStyle(
                          color: fg,
                          fontSize: 12.0,
                          fontWeight: FontWeight.w500,
                          fontFamily: BTTypography.fontFamily,
                          height: 16 / 12,
                          letterSpacing: 0,
                        ),
                      ),
                    if (widget.rightIcon != null) ...[
                      SizedBox(width: gap),
                      IconTheme(
                        data: IconThemeData(size: 16, color: fg),
                        child: widget.rightIcon!,
                      ),
                    ],
                  ],
                );
              }

              // Explicit width/height are passed so the AnimatedContainer
              // inside BTInnerShadowContainer's Stack is always given a
              // fixed size — without them the Stack's loose constraints can
              // cause the container to under-size and shift content off-center.
              return BTInnerShadowContainer(
                borderRadius: radius,
                backgroundColor: bg,
                border: border,
                // icon-only with addon: no fixed dimensions — content+padding drives size.
                // plain icon-only: fixed square.
                // regular: fixed height, intrinsic width.
                width: (isIconOnly && !hasAddon) ? btnSize : null,
                height: hasAddon ? null : btnSize,
                // Always enabled — alpha in shadowColor controls visibility.
                isShadowTopLeft: !_disabled,
                isShadowTopRight: !_disabled,
                shadowColor: shadowColor,
                blur: BTShadow.button.pressed.first.blurRadius,
                offset: BTShadow.button.pressed.first.offset,
                alignment: Alignment.center,
                // Duration.zero — we drive all animation via AnimatedBuilder;
                // any internal animation in BTInnerShadowContainer would lag.
                animationDuration: Duration.zero,
                // icon-only (no addon): Center fills the full square area.
                // icon-only (with addon): Padding drives layout like regular.
                // regular: Padding drives the label layout as before.
                child: (isIconOnly && !hasAddon)
                    ? Center(child: content)
                    : Padding(padding: padding, child: content),
              );
            },
          ),
        ),
      ),
    );

    // Enforce exact dimensions:
    // - plain icon-only: fixed square (w & h = btnSize)
    // - icon-only with addon: no outer constraint — padding+content drives size
    // - regular: fixed height only, width stays intrinsic
    if (isIconOnly && !hasAddon) {
      return SizedBox.square(dimension: btnSize, child: button);
    }
    if (hasAddon) {
      return button; // unconstrained — content + padding determines size
    }
    return SizedBox(height: btnSize, child: button);
  }
}

// Button color logic — Figma node 114:2645.
// All colors resolved from btech semantic tokens via BuildContext.
// Do NOT hardcode Color(0xFF...) here.

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/button/button.types.dart';
import 'package:flutter/material.dart';

/// Resolves background, foreground and border colors for the given
/// [variant] and interaction [state].
({Color bg, Color fg, Color? border}) buttonColors({
  required BTButtonVariant variant,
  required BTButtonState state,
  required BTColorTheme colors,
}) {
  return switch ((variant, state)) {
    // ── Primary ──────────────────────────────────────────────────────────────
    (BTButtonVariant.primary, BTButtonState.disabled) => (
        bg: colors.bg.subtlest,
        fg: colors.text.inverse,
        border: null,
      ),
    (BTButtonVariant.primary, BTButtonState.hoverOrPressed) => (
        bg: colors.brand.primaryBold,
        fg: colors.text.inverse,
        border: null,
      ),
    (BTButtonVariant.primary, _) => (
        bg: colors.brand.primary,
        fg: colors.text.inverse,
        border: null,
      ),

    // ── Secondary Light (grey bg) ─────────────────────────────────────────────
    (BTButtonVariant.secondaryLight, BTButtonState.disabled) => (
        bg: colors.bg.subtle,
        fg: colors.bg.subtlest,
        border: null,
      ),
    (BTButtonVariant.secondaryLight, BTButtonState.hoverOrPressed) => (
        bg: colors.bg.subtler,
        fg: colors.text.primary,
        border: null,
      ),
    (BTButtonVariant.secondaryLight, _) => (
        bg: colors.bg.secondary,
        fg: colors.text.primary,
        border: null,
      ),

    // ── Secondary White (white bg + border) ───────────────────────────────────
    (BTButtonVariant.secondaryWhite, BTButtonState.disabled) => (
        bg: colors.bg.primary,
        fg: colors.bg.subtlest,
        border: colors.bg.subtlest,
      ),
    (BTButtonVariant.secondaryWhite, BTButtonState.hoverOrPressed) => (
        bg: colors.bg.subtler,
        fg: colors.text.primary,
        border: colors.border.primary,
      ),
    (BTButtonVariant.secondaryWhite, _) => (
        bg: colors.bg.primary,
        fg: colors.text.primary,
        border: colors.border.primary,
      ),

    // ── Destructive ──────────────────────────────────────────────────────────
    (BTButtonVariant.destructive, BTButtonState.disabled) => (
        bg: colors.bg.subtlest,
        fg: colors.text.inverse,
        border: null,
      ),
    (BTButtonVariant.destructive, BTButtonState.hoverOrPressed) => (
        bg: colors.ext.errorBold,
        fg: colors.text.inverse,
        border: null,
      ),
    (BTButtonVariant.destructive, _) => (
        bg: colors.ext.error,
        fg: colors.text.inverse,
        border: null,
      ),

    // ── Outline ──────────────────────────────────────────────────────────────
    (BTButtonVariant.outline, BTButtonState.disabled) => (
        bg: Colors.transparent,
        fg: colors.bg.subtlest,
        border: colors.bg.subtlest,
      ),
    (BTButtonVariant.outline, BTButtonState.hoverOrPressed) => (
        bg: colors.bg.subtler,
        fg: colors.text.primary,
        border: colors.border.primary,
      ),
    (BTButtonVariant.outline, _) => (
        bg: Colors.transparent,
        fg: colors.text.primary,
        border: colors.border.primary,
      ),

    // ── Ghost ────────────────────────────────────────────────────────────────
    (BTButtonVariant.ghost, BTButtonState.disabled) => (
        bg: Colors.transparent,
        fg: colors.bg.subtlest,
        border: null,
      ),
    (BTButtonVariant.ghost, BTButtonState.hoverOrPressed) => (
        bg: colors.bg.subtler,
        fg: colors.text.primary,
        border: null,
      ),
    (BTButtonVariant.ghost, _) => (
        bg: Colors.transparent,
        fg: colors.text.primary,
        border: null,
      ),
  };
}

/// Interaction state used for color resolution.
enum BTButtonState { idle, hoverOrPressed, disabled }

extension BTButtonStateExt on BTButtonState {
  static BTButtonState of({
    required bool disabled,
    required bool hovered,
    required bool pressed,
  }) {
    if (disabled) return BTButtonState.disabled;
    if (hovered || pressed) return BTButtonState.hoverOrPressed;
    return BTButtonState.idle;
  }
}

// BTech UI — InnerShadowContainer
// A Stack-based widget that draws an inner shadow via CustomPaint.
//
// Flutter's built-in BoxShadow(blurStyle: BlurStyle.inner) does not animate
// cleanly and cannot lerp with BoxDecoration.  This widget uses the same
// clip-and-translate CustomPainter technique as buma_design_system's
// InnerShadowContainer so the button pressed state is visually identical.
//
// Animation is CALLER-DRIVEN: this widget is intentionally stateless and
// contains no AnimationController.  The caller (e.g. BTButton's
// AnimatedBuilder) lerps backgroundColor and shadowColor each frame and
// rebuilds this widget with the interpolated values.  The painter
// short-circuits immediately when shadowColor.alpha == 0, so there is
// zero overdraw at rest.
//
// [animationDuration] and [animationCurve] are accepted for API
// compatibility but are intentionally ignored — they were used by the old
// AnimatedContainer/AnimatedOpacity approach which caused double-rebuild
// flicker.
//
// Usage:
// ```dart
// BTInnerShadowContainer(
//   borderRadius: context.btRadius.sm,
//   backgroundColor: bg,          // already lerped by caller
//   isShadowTopLeft: showShadow,
//   isShadowTopRight: showShadow,
//   shadowColor: shadowColor,      // alpha encodes opacity — 0x00 = no draw
//   blur: 4,
//   offset: const Offset(0, 4),
//   animationDuration: Duration.zero,
//   child: content,
// )
// ```

import 'package:flutter/material.dart';

/// A stateless container that renders an inner (inset) shadow via
/// [CustomPaint].
///
/// All animation is caller-driven — the caller lerps [backgroundColor] and
/// [shadowColor] each frame.  When [shadowColor] has `alpha == 0` the painter
/// exits immediately (no overdraw).  [animationDuration] and [animationCurve]
/// are accepted but ignored.
///
/// Toggle [isShadowTopLeft] / [isShadowTopRight] / [isShadowBottomLeft] /
/// [isShadowBottomRight] to enable the shadow from the corresponding edge.
class BTInnerShadowContainer extends StatelessWidget {
  /// Creates a [BTInnerShadowContainer].
  const BTInnerShadowContainer({
    super.key,
    this.height,
    this.width,
    this.border,
    this.borderRadius = 8.0,
    this.backgroundColor = Colors.white,
    this.isShadowTopLeft = false,
    this.isShadowTopRight = false,
    this.isShadowBottomRight = false,
    this.isShadowBottomLeft = false,
    this.blur = 4.0,
    this.offset = const Offset(0, 4),
    this.shadowColor = Colors.black26,
    this.child,
    this.alignment = Alignment.center,
    this.animationDuration = const Duration(milliseconds: 200),
    this.animationCurve = Curves.linear,
  });

  /// The height of the container.
  final double? height;

  /// The width of the container.
  final double? width;

  /// Optional border drawn beneath the shadow layer.
  final BoxBorder? border;

  /// Corner radius in logical pixels.
  final double borderRadius;

  /// Background fill colour.
  final Color backgroundColor;

  /// Show inner shadow from the top-left corner.
  final bool isShadowTopLeft;

  /// Show inner shadow from the top-right corner.
  final bool isShadowTopRight;

  /// Show inner shadow from the bottom-right corner.
  final bool isShadowBottomRight;

  /// Show inner shadow from the bottom-left corner.
  final bool isShadowBottomLeft;

  /// Gaussian blur radius (matches CSS blur value 1:1).
  final double blur;

  /// Offset of the shadow relative to the container edge.
  final Offset offset;

  /// Colour of the shadow.
  final Color shadowColor;

  /// Widget rendered inside the container.
  final Widget? child;

  /// How the child is aligned inside the container.
  final AlignmentGeometry alignment;

  /// Duration for background colour + shadow visibility transitions.
  final Duration animationDuration;

  /// Animation curve for the transitions.
  final Curve animationCurve;

  @override
  Widget build(BuildContext context) {
    final hasShadow = isShadowTopLeft ||
        isShadowTopRight ||
        isShadowBottomRight ||
        isShadowBottomLeft;
    return Stack(
      children: [
        // Plain Container — animation is driven externally by the caller.
        AnimatedContainer(
          duration: animationDuration,
          curve: animationCurve,
          height: height,
          width: width,
          alignment: alignment,
          decoration: BoxDecoration(
            color: backgroundColor,
            borderRadius: BorderRadius.circular(borderRadius),
            border: border,
          ),
          child: child,
        ),
        Positioned.fill(
          child: AnimatedOpacity(
            duration: animationDuration,
            curve: animationCurve,
            opacity: hasShadow ? 1.0 : 0.0,
            child: ClipRRect(
              borderRadius: BorderRadius.circular(borderRadius),
              child: CustomPaint(
                painter: _BTInnerShadowPainter(
                  shadowColor: shadowColor,
                  blur: blur,
                  offset: offset,
                  borderRadius: borderRadius,
                  isShadowTopLeft: isShadowTopLeft,
                  isShadowTopRight: isShadowTopRight,
                  isShadowBottomRight: isShadowBottomRight,
                  isShadowBottomLeft: isShadowBottomLeft,
                ),
              ),
            ),
          ),
        ),
      ],
    );
  }
}

// ── Painter ───────────────────────────────────────────────────────────────

class _BTInnerShadowPainter extends CustomPainter {
  const _BTInnerShadowPainter({
    required this.shadowColor,
    required this.blur,
    required this.offset,
    required this.borderRadius,
    this.isShadowTopLeft = false,
    this.isShadowTopRight = false,
    this.isShadowBottomRight = false,
    this.isShadowBottomLeft = false,
  });

  final Color shadowColor;
  final double blur;
  final Offset offset;
  final double borderRadius;
  final bool isShadowTopLeft;
  final bool isShadowTopRight;
  final bool isShadowBottomRight;
  final bool isShadowBottomLeft;

  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = shadowColor
      ..maskFilter = MaskFilter.blur(BlurStyle.normal, blur);

    final rect = Offset.zero & size;
    final rrect = RRect.fromRectAndRadius(rect, Radius.circular(borderRadius));

    final outer = Path()
      ..addRect(
        Rect.fromLTRB(
          -size.width,
          -size.height,
          size.width * 2,
          size.height * 2,
        ),
      );

    final inner = Path()
      ..addRRect(rrect)
      ..fillType = PathFillType.evenOdd;

    canvas.saveLayer(rect, Paint());

    void drawShadow(double dx, double dy) {
      canvas
        ..save()
        ..translate(dx, dy)
        ..drawPath(
          Path.combine(PathOperation.difference, outer, inner),
          paint,
        )
        ..restore();
    }

    if (isShadowBottomRight) drawShadow(-offset.dx.abs(), -offset.dy.abs());
    if (isShadowBottomLeft) drawShadow(offset.dx.abs(), -offset.dy.abs());
    if (isShadowTopLeft) drawShadow(offset.dx.abs(), offset.dy.abs());
    if (isShadowTopRight) drawShadow(-offset.dx.abs(), offset.dy.abs());

    canvas.restore();
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => true;
}
